import { createDebounce } from './task09';

describe('createDebounce', () => {
  it('delays execution', (done) => {
    let called = false;
    const debounced = createDebounce(() => { called = true; }, 50);
    debounced();
    expect(called).toBe(false);
    setTimeout(() => {
      expect(called).toBe(true);
      done();
    }, 100);
  });

  it('calls only once for rapid calls', (done) => {
    let count = 0;
    const debounced = createDebounce(() => { count++; }, 50);
    debounced();
    debounced();
    debounced();
    setTimeout(() => {
      expect(count).toBe(1);
      done();
    }, 100);
  });
});
